  template <class Ntk, unsigned CutSize, typename CutData, unsigned NInputs, classification_type Configuration>
  template <bool DO_AREA>
  void tech_map_impl<Ntk, CutSize, CutData, NInputs, Configuration>::match_phase(node<Ntk> const &n, uint8_t phase) {
    // Hybrid approach combining population and simulated annealing
    const int POPULATION_SIZE = 5;
    struct Solution {
        double arrival;
        double area_flow;
        float area;
        uint32_t size;
        uint8_t cut;
        uint8_t phase;
    };
    Solution best_solutions[POPULATION_SIZE];

    // Initialize population with more meaningful diversity
    for (int i = 0; i < POPULATION_SIZE; i++) {
        best_solutions[i] = {
            std::numeric_limits<double>::max() * (1.0 + 0.05*i), // Smaller steps for better granularity
            std::numeric_limits<double>::max() * (1.0 + 0.05*i),
            std::numeric_limits<float>::max() * (1.0 + 0.05*i),
            UINT32_MAX,
            static_cast<uint8_t>(i % cuts.cuts(index).size()), // Spread across different cuts
            static_cast<uint8_t>(rand() % 2) // Random phases for better exploration
        };
    }

    // Simulated annealing parameters
    static double temperature = 100.0;
    const double cooling_rate = 0.99;
    uint8_t cut_index = 0u;
    auto index = ntk.node_to_index(n);

    auto &node_data = node_match[index];
    auto &cut_matches = matches[index];
    supergate<NInputs> const *best_supergate = node_data.best_supergate[phase];

    /* recompute best match info */
    if (best_supergate != nullptr) {
      auto const &cut = cuts.cuts(index)[node_data.best_cut[phase]];

      best_phase = node_data.phase[phase];
      best_arrival = 0.0f;
      best_area_flow = best_supergate->area + cut_leaves_flow(cut, n, phase);
      best_area = best_supergate->area;
      best_cut = node_data.best_cut[phase];
      best_size = cut.size();

      auto ctr = 0u;
      for (auto l : cut) {
        double arrival_pin = node_match[l].arrival[(best_phase >> ctr) & 1] + best_supergate->tdelay[ctr];
        best_arrival = std::max(best_arrival, arrival_pin);
        ++ctr;
      }
    }

    /* Calculate total weight for probabilistic selection */
    double total_weight = 0.0;
    for (auto &cut : cuts.cuts(index)) {
        total_weight += 1.0 / (cut->size() + 1);
    }

    /* foreach cut with probabilistic selection */
    for (auto &cut : cuts.cuts(index)) {
        // Probability-based selection
        double cut_weight = (1.0 / (cut->size() + 1)) / total_weight;
        if (rand()/(double)RAND_MAX > cut_weight) continue;
      /* trivial cuts or not matched cuts */
      if ((*cut)->data.ignore) {
        ++cut_index;
        continue;
      }

      auto const &supergates = cut_matches[(*cut)->data.match_index].supergates;
      auto const negation = cut_matches[(*cut)->data.match_index].negations[phase];

      if (supergates[phase] == nullptr) {
        ++cut_index;
        continue;
      }

      /* match each gate and take the best one */
      for (auto const &gate : *supergates[phase]) {
        uint8_t gate_polarity = gate.polarity ^ negation;
        node_data.phase[phase] = gate_polarity;
        double area_local = gate.area + cut_leaves_flow(*cut, n, phase);
        double worst_arrival = 0.0f;

        auto ctr = 0u;
        for (auto l : *cut) {
          double arrival_pin = node_match[l].arrival[(gate_polarity >> ctr) & 1] + gate.tdelay[ctr];
          worst_arrival = std::max(worst_arrival, arrival_pin);
          ++ctr;
        }

        if constexpr (DO_AREA) {
          if (worst_arrival > node_data.required[phase] + epsilon)
            continue;
        }

        // Check against all solutions with probabilistic acceptance
        for (int i = 0; i < POPULATION_SIZE; i++) {
            // Weighted acceptance criteria based on iteration progress
            double weight = 1.0 - (i / (double)POPULATION_SIZE);
            bool accept = compare_map<DO_AREA>(worst_arrival, best_solutions[i].arrival, 
                                            area_local, best_solutions[i].area_flow, 
                                            cut->size(), best_solutions[i].size);

            // Enhanced simulated annealing with weighted probabilities
            if (!accept && temperature > 0.1) {
                double arrival_delta = (worst_arrival - best_solutions[i].arrival) / (best_solutions[i].arrival + 1e-6);
                double area_delta = (area_local - best_solutions[i].area_flow) / (best_solutions[i].area_flow + 1e-6);
                double delta = 0.6 * arrival_delta + 0.4 * area_delta; // Weighted combination
                double probability = exp(-delta / (temperature * weight));
                accept = (rand() / (double)RAND_MAX) < probability;
            }

            if (accept) {
                best_solutions[i] = {
                    worst_arrival,
                    area_local,
                    gate.area,
                    cut->size(),
                    cut_index,
                    gate_polarity
                };
                break;
            }
        }
        // Adaptive cooling based on progress
        static int improvement_count = 0;
        static double last_best_arrival = std::numeric_limits<double>::max();
        if (best_solutions[0].arrival < last_best_arrival) {
            improvement_count++;
            last_best_arrival = best_solutions[0].arrival;
        }

        // Adjust cooling rate based on recent improvements
        double adaptive_cooling = cooling_rate;
        if (improvement_count < 10) {
            adaptive_cooling = 0.995; // Cool slower if making progress
        } else {
            adaptive_cooling = 0.97; // Cool faster if progress stalls
        }
        temperature *= adaptive_cooling;
      }

      ++cut_index;
    }

    // Adaptive restart mechanism based on population diversity
    static int restart_counter = 0;
    restart_counter++;

    // Calculate population diversity
    double avg_arrival = 0.0, avg_area = 0.0;
    for (int i = 0; i < POPULATION_SIZE; i++) {
        avg_arrival += best_solutions[i].arrival;
        avg_area += best_solutions[i].area_flow;
    }
    avg_arrival /= POPULATION_SIZE;
    avg_area /= POPULATION_SIZE;

    // Trigger restart based on convergence and temperature
    if ((restart_counter > 500 && temperature < 0.1) || 
        (avg_arrival < 1.1 * best_solutions[0].arrival && avg_area < 1.1 * best_solutions[0].area_flow)) {
        restart_counter = 0;
        temperature = 100.0 * (0.8 + 0.4 * (rand() / (double)RAND_MAX)); // Randomize restart temperature

        // Reset solutions while keeping the best one
        for (int i = 1; i < POPULATION_SIZE; i++) {
            best_solutions[i] = {
                best_solutions[0].arrival * (1.0 + 0.1 * (i+1)),
                best_solutions[0].area_flow * (1.0 + 0.1 * (i+1)),
                best_solutions[0].area * (1.0 + 0.1 * (i+1)),
                UINT32_MAX,
                static_cast<uint8_t>(rand() % cuts.cuts(index).size()),
                static_cast<uint8_t>(rand() % 2)
            };
        }
    }

    // Select best solution from population
    Solution best_solution = best_solutions[0];
    for (int i = 1; i < POPULATION_SIZE; i++) {
        if (compare_map<DO_AREA>(best_solutions[i].arrival, best_solution.arrival,
                               best_solutions[i].area_flow, best_solution.area_flow,
                               best_solutions[i].size, best_solution.size)) {
            best_solution = best_solutions[i];
        }
    }

    node_data.flows[phase] = best_solution.area_flow;
    node_data.arrival[phase] = best_solution.arrival;
    node_data.area[phase] = best_solution.area;
    node_data.best_cut[phase] = best_solution.cut;
    node_data.phase[phase] = best_solution.phase;
  }

